const express = require('express');
const app = express();

// Middleware to log requests including API keys
app.use((req, res, next) => {
    console.log(`${new Date().toISOString()} - ${req.url} - API Key: ${req.query.api_key}`);
    next();
});

// Middleware to parse JSON request bodies
app.use(express.json());

// Function to validate API key
function validateApiKey(apiKey) {
    // Replace this with your actual key validation logic
    const validKeys = ['your_valid_key1', 'your_valid_key2'];
    return validKeys.includes(apiKey);
}

// Forward requests to backend services with API keys
app.all('/*', (req, res, next) => {
    if (!validateApiKey(req.query.api_key)) {
        return res.status(401).json({ error: 'Invalid API key' });
    }

    // Forward the request to the specified endpoint
    const targetUrl = `http://backend-service.com/${req.url}`;
    req.pipe(require('request')).end((err) => {
        if (err) return res.status(500).json({ error: err });
        res.json(res); // Assume the backend service returns JSON data
    });

    // Set the API key in request headers and forward it to the backend service
    req.headers['x-api-key'] = req.query.api_key;
});

// Start the server on port 3000
app.listen(3000, () => console.log('API Gateway listening on port 3000'));